import{_ as t,c as a,o,ag as i}from"./chunks/framework.C_7JoTpM.js";const m=JSON.parse('{"title":"TEST 2 - THE BLACK BOX: Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"week2/pole-electronic/index.md","filePath":"week2/pole-electronic/index.md"}'),r={name:"week2/pole-electronic/index.md"};function n(s,e,l,c,h,d){return o(),a("div",null,e[0]||(e[0]=[i('<h1 id="test-2-the-black-box-documentation" tabindex="-1">TEST 2 - THE BLACK BOX: Documentation <a class="header-anchor" href="#test-2-the-black-box-documentation" aria-label="Permalink to &quot;TEST 2 - THE BLACK BOX: Documentation&quot;">​</a></h1><p>In this documentation:</p><ul><li><a href="#1-general-context">1. General Context</a></li><li><a href="#2-description-of-components">2. Description of components</a></li><li><a href="#3-computer-aided-design">3. Computer-Aided Design</a></li><li><a href="#4-computer-aided-manufacturing">4. Computer-Aided Manufacturing</a></li><li><a href="#5-embedded-software-and-microcontroller-logic">5. Embedded Software and Microcontroller Logic</a></li><li><a href="#6-programming-the-circuits">6. Programming the circuits</a></li><li><a href="#7-assembly-of-components">7. Assembly of components</a></li><li><a href="#8-testing-the-project">8. Testing the project</a></li><li><a href="#9-helpful-Ressources">9. Helpful Ressources</a></li></ul><h2 id="_1-general-context" tabindex="-1">1. General Context <a class="header-anchor" href="#_1-general-context" aria-label="Permalink to &quot;1. General Context&quot;">​</a></h2><p>Black boxes are critical devices commonly used in fields such as aviation, automotive, and rail transport to record and monitor key operational data from equipment. By continuously collecting information like speed, position, and orientation, these systems help in understanding how machines behave and can provide useful insights in case of incidents or for performance improvement. The goal here is to develop a compact black box capable of capturing motion data, including speed and position, using a gyroscope and accelerometer sensor.</p><p>This second test of the Tekbot Robotics Challenge introduces the design and implementation of a simple embedded black box system. The goal here is to develop a compact black box capable of capturing motion data, including speed and posit+ion, using a gyroscope and accelerometer sensor. The collected data should be sent in real-time to a control station, where it can be displayed and analyzed. The project provides hands-on experience with embedded systems, data transmission, and hardware-software integration.</p><h3 id="objectives-of-the-test" tabindex="-1">Objectives of the test <a class="header-anchor" href="#objectives-of-the-test" aria-label="Permalink to &quot;Objectives of the test&quot;">​</a></h3><ul><li><strong>Accurately capture and record motion data:</strong> Measure and record the speed and position of the cube as it moves, using sensor input.</li><li><strong>Enable real-time data transmission:</strong> Continuously send the collected data to the control station without delay.</li><li><strong>Facilitate clear and immediate data visualization:</strong> Present the motion information on a display so users can quickly understand the cube’s movements.</li><li><strong>Demonstrate system reliability and robustness:</strong> Show that the system works smoothly and provides dependable results during testing.</li><li><strong>Encourage hands-on integration of skills:</strong> Offer an opportunity to integrate knowledge of embedded systems, sensor data handling, and system integration through a hands-on project.</li></ul><h2 id="_2-description-of-components" tabindex="-1">2. Description of components <a class="header-anchor" href="#_2-description-of-components" aria-label="Permalink to &quot;2. Description of components &lt;!-- add real images --&gt;&quot;">​</a></h2><h3 id="a-the-atmega328p-microcontroller" tabindex="-1">a. The ATmega328P microcontroller <a class="header-anchor" href="#a-the-atmega328p-microcontroller" aria-label="Permalink to &quot;a. The ATmega328P microcontroller&quot;">​</a></h3><p>The <a href="https://ww1.microchip.com/downloads/aemDocuments/documents/MCU08/ProductDocuments/DataSheets/ATmega48A-PA-88A-PA-168A-PA-328-P-DS-DS40002061B.pdf" target="_blank" rel="noreferrer">ATmega328P</a> is an 8-bit <a href="https://www.geeksforgeeks.org/digital-logic/microcontroller-and-its-types/" target="_blank" rel="noreferrer">microcontroller</a> chip that serves as the <strong>central processing unit</strong> in many electronic devices. It is based on the <a href="https://en.wikipedia.org/wiki/AVR_microcontrollers" target="_blank" rel="noreferrer">AVR architecture</a> and is designed for tasks that involve reading sensor data, controlling outputs like LEDs or motors, and communicating or exchanging information with other devices. It is the chip used in the popular <a href="https://docs.arduino.cc/hardware/uno-rev3/" target="_blank" rel="noreferrer">Arduino UNO board</a>.</p><p align="center"><img src="https://github.com/user-attachments/assets/403a51b1-f52f-4d34-8fca-dbdd6fee4f12" width="500"></p><h4 id="key-features" tabindex="-1">KEY FEATURES <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;KEY FEATURES&quot;">​</a></h4><ul><li><strong>CPU:</strong> 8-bit AVR architecture running at up to 20 MHz (handles calculations and instructions quickly and efficiently)</li><li><strong>Memory:</strong> Flash Memory (32 KB), SRAM (2 KB), EEPROM (1 KB) for data and main program storing</li><li><strong>GPIO Pins:</strong> 23 programmable input/output pins for reading signals</li><li><strong>Timers:</strong> Three built-in timers (two 8-bit, one 16-bit)</li><li><strong>Analog Inputs:</strong> 6 pins for reading changing electrical signals</li><li><strong>Communication interfaces:</strong> Supports USART (serial comminication), I2C and SPI protocols</li><li><strong>PWM:</strong> 6 channels for Pulse Width Modulation</li><li><strong>Operating Voltage:</strong> Works with power supplies from 1.8V to 5.5V</li><li><strong>Low Power Modes:</strong> Multiple sleep modes for energy efficiency</li></ul><h3 id="b-the-mpu-6050-gyroscope-and-accelerometer-in-one-sensor" tabindex="-1">b. The MPU-6050: gyroscope and accelerometer in one sensor <a class="header-anchor" href="#b-the-mpu-6050-gyroscope-and-accelerometer-in-one-sensor" aria-label="Permalink to &quot;b. The MPU-6050: gyroscope and accelerometer in one sensor&quot;">​</a></h3><p>The <a href="https://www.allelcoelec.com/blog/mpu-6050-in-action-practical-guide-to-setup%2Cconfiguration%2Cand-noise-management.html?srsltid=AfmBOooVL5CkBlAuw8WV0Yz7l7ZA2u8Ld6yBZFQf7kaTwiemNMmpUUey&amp;utm_source=chatgpt.com#8.%20MPU-6050-Based%20Motion%20Trajectory%20Calculation" target="_blank" rel="noreferrer">MPU-6050</a> is a sensor module that combines a 3-axis gyroscope and a 3-axis accelerometer, enabling the detection of both rotational movement and linear acceleration in three dimensions. It features a Digital Motion Processor (DMP), which processes the raw sensor data using built-in algorithms to deliver reliable information on speed, rotation, and orientation. Communication with microcontrollers is accomplished via the I2C protocol, allowing for smooth integration into embedded systems. With its ability to provide real-time, accurate measurements while minimizing the processing load on the main system, the MPU-6050 is well suited for applications that require motion tracking and analysis.</p><p align="center"><img src="https://github.com/user-attachments/assets/d76a29bc-0cd0-4bb3-a4a2-e1efaf1bdac3" width="500"></p><h3 id="c-the-lcd-screen" tabindex="-1">c. The LCD screen <a class="header-anchor" href="#c-the-lcd-screen" aria-label="Permalink to &quot;c. The LCD screen&quot;">​</a></h3><p>The <a href="https://en.wikipedia.org/wiki/Liquid-crystal_display" target="_blank" rel="noreferrer">Liquid-Crystal Display</a> (LCD) is a type of screen found in many electronic devices, like calculators, clocks, and TVs. It works by using a thin layer of liquid crystals placed between two filters. These crystals can change how light passes through them when electricity is applied. The LCD itself does not create light. Instead, a light behind the screen (called a backlight) shines through the crystals. By controlling the crystals with electrical signals, the LCD can show different shapes, letters, or pictures in black and white or in color.</p><p align="center"><img src="https://github.com/user-attachments/assets/d16d5dc1-02c4-456c-839f-8a997d4395e6" width="500"></p><h3 id="d-the-zener-diode" tabindex="-1">d. The Zener Diode <a class="header-anchor" href="#d-the-zener-diode" aria-label="Permalink to &quot;d. The Zener Diode&quot;">​</a></h3><p>The <a href="https://en.wikipedia.org/wiki/Zener_diode" target="_blank" rel="noreferrer">Zener Diode</a> is a special type of semiconductor diode that is designed to allow current to flow in the reverse direction when the voltage across it reaches a specific value, called the Zener breakdown voltage. What this means is that a Zener diode can maintain a constant voltage in a circuit, even if the input voltage changes. When the voltage across the Zener diode exceeds its breakdown voltage, it starts conducting in reverse and keeps the voltage steady, making it very useful for voltage regulation and protecting sensitive electronic components from voltage spikes.</p><p align="center"><img src="https://github.com/user-attachments/assets/ff801b0f-7cb2-41a0-b1c1-73a898b3c432" width="500"></p><h3 id="e-the-lm-1950-a-voltage-regulator" tabindex="-1">e. The LM-1950: a voltage regulator <a class="header-anchor" href="#e-the-lm-1950-a-voltage-regulator" aria-label="Permalink to &quot;e. The LM-1950: a voltage regulator&quot;">​</a></h3><p>The <a href="https://www.alldatasheet.com/datasheet-pdf/view/125278/NSC/LM1950.html" target="_blank" rel="noreferrer">LM-1950</a> is a <a href="https://en.wikipedia.org/wiki/Voltage_regulator" target="_blank" rel="noreferrer">voltage regulator</a>. Its purpose to keep the voltage at a constant level. It uses a negative feedback system to monitor and adjust the output, ensuring stable voltage even when the input voltage or load conditions change. As an electronic component, it is built using integrated circuitry rather than mechanical parts. The LM-1950 is intended for regulating DC voltages, and can be used to supply a steady voltage to one or more DC-powered devices.</p><h3 id="f-the-cube-black-box" tabindex="-1">f. The Cube (black box) <a class="header-anchor" href="#f-the-cube-black-box" aria-label="Permalink to &quot;f. The Cube (black box)&quot;">​</a></h3><p>For this test, the black box will be represented by a <strong>cube</strong>. It will be mainly composed of the MPU-6050 sensor and the ATmega328P chip mounted on a Printed Circuit Board (PCB). The main functions of the cube will be the acquisition of movement data and the transmission of this data to the Control Station via an I2C bus.</p><h3 id="g-the-control-station" tabindex="-1">g. The Control Station <a class="header-anchor" href="#g-the-control-station" aria-label="Permalink to &quot;g. The Control Station&quot;">​</a></h3><p>The Control Station&#39;s main tasks are the processing and displaying of the data it receives from <strong>the cube</strong>. It will be composed of another ATmega328P chip mounted on a dedicated PCB and the LCD screen.</p><h3 id="h-our-custom-power-supply" tabindex="-1">h. Our custom power supply <a class="header-anchor" href="#h-our-custom-power-supply" aria-label="Permalink to &quot;h. Our custom power supply&quot;">​</a></h3><p>To power up our setup, we should build a power supply that is independent from the cube and that will provide safe and sufficient voltage to all the components. For that, we will use:</p><h2 id="_3-computer-aided-design" tabindex="-1">3. Computer-Aided Design <a class="header-anchor" href="#_3-computer-aided-design" aria-label="Permalink to &quot;3. Computer-Aided Design&quot;">​</a></h2><h3 id="a-kicad-schematic-diagrams" tabindex="-1">a. KiCad schematic diagrams <a class="header-anchor" href="#a-kicad-schematic-diagrams" aria-label="Permalink to &quot;a. KiCad schematic diagrams&quot;">​</a></h3><p>We used the KiCad EDA (<em>download <a href="https://www.kicad.org/" target="_blank" rel="noreferrer">here</a></em>) to design and document the schematic for this project. KiCad is a powerful, open-source Electronic Design Automation (EDA) suite that enables users to create professional-quality schematics and printed circuit boards. It offers a comprehensive set of tools for circuit design, simulation, and layout, making it ideal for both hobbyists and professionals. For more detailed information about using KiCad and its features, you can refer to the <a href="https://docs.kicad.org/" target="_blank" rel="noreferrer">official documentation</a>.</p><p>Below is the KiCad schematics diagram for this project:</p><h4 id="the-black-box" tabindex="-1">The black box <a class="header-anchor" href="#the-black-box" aria-label="Permalink to &quot;The black box&quot;">​</a></h4><h4 id="the-control-station" tabindex="-1">The Control station <a class="header-anchor" href="#the-control-station" aria-label="Permalink to &quot;The Control station&quot;">​</a></h4><h3 id="b-printed-circuit-board-pcb-design" tabindex="-1">b. Printed Circuit Board (PCB) design <a class="header-anchor" href="#b-printed-circuit-board-pcb-design" aria-label="Permalink to &quot;b. Printed Circuit Board (PCB) design&quot;">​</a></h3><p>We also used the KiCad EDA to design and layout the printed circuit board (PCB) for this project. Below, you will find the detailed PCB designs realized in KiCad:</p><h4 id="the-black-box-1" tabindex="-1">The black box <a class="header-anchor" href="#the-black-box-1" aria-label="Permalink to &quot;The black box&quot;">​</a></h4><h4 id="the-control-station-1" tabindex="-1">The Control station <a class="header-anchor" href="#the-control-station-1" aria-label="Permalink to &quot;The Control station&quot;">​</a></h4><h3 id="c-the-cube-design" tabindex="-1">c. The Cube design <a class="header-anchor" href="#c-the-cube-design" aria-label="Permalink to &quot;c. The Cube design&quot;">​</a></h3><p>For the cube design, we used Autodesk Fusion 360 (<em>download <a href="https://www.autodesk.com/products/fusion-360/download" target="_blank" rel="noreferrer">here</a></em>) to design and model the components for this project. Fusion 360 is a comprehensive, cloud-based platform that integrates design, engineering, and manufacturing into a single tool. It offers powerful features for parametric modeling, assembly creation, simulation, and detailed rendering, making it ideal for both prototyping and final product development. To learn more about this tool, refer to its <a href="https://help.autodesk.com/view/fusion360/ENU/" target="_blank" rel="noreferrer">official documentation</a>.</p><h2 id="_4-computer-aided-manufacturing" tabindex="-1">4. Computer-Aided Manufacturing <a class="header-anchor" href="#_4-computer-aided-manufacturing" aria-label="Permalink to &quot;4. Computer-Aided Manufacturing&quot;">​</a></h2><h2 id="_5-microcontroller-logic-on-the-i2c-bus" tabindex="-1">5. Microcontroller Logic on the I2C bus <a class="header-anchor" href="#_5-microcontroller-logic-on-the-i2c-bus" aria-label="Permalink to &quot;5. Microcontroller Logic on the I2C bus&quot;">​</a></h2><h3 id="a-what-is-i2c" tabindex="-1">a. What is I2C ? <a class="header-anchor" href="#a-what-is-i2c" aria-label="Permalink to &quot;a. What is I2C ?&quot;">​</a></h3><p>The <a href="https://en.wikipedia.org/wiki/I%C2%B2C" target="_blank" rel="noreferrer">Inter-Integrated Circuit</a> (I2C), is a communication protocol that allows multiple electronic components, like sensors and microcontrollers, to talk to each other using just two wires: one for data (SDA) and one for the clock signal (SCL). With I2C, a single device acts as the controller (or master) that manages the communication, while other devices act as followers (or slaves). Each device on the I2C bus has a unique address, so the controller can talk to each one individually, even though they share the same wires. This makes I2C a simple and efficient way to connect many devices together in a circuit, saving wiring and making communication between parts much easier.</p><h3 id="b-microcontroller-configuration" tabindex="-1">b. Microcontroller configuration <a class="header-anchor" href="#b-microcontroller-configuration" aria-label="Permalink to &quot;b. Microcontroller configuration &lt;!-- and sensor data acquisition/processing --&gt;&quot;">​</a></h3><p>The microcontroller configuration is one of the core aspects of this test. It ensures seamless communication between components, accurate data collection from sensors, and reliable transmission of information to the control station, forming the foundation of the system’s functionality.</p><p>In this project, two microcontrollers ATmega328P are used.</p><ul><li>The <strong>Cube microcontroller</strong> is configured as the I2C master. It is responsible for collecting motion data from the MPU-6050 sensor (which acts as an I2C slave), processing this data, and sending it to the control station.</li><li>The <strong>Control station microcontroller</strong> is also configured as an I2C slave, listening for incoming data from the cube.</li></ul><p>The LCD screen is directly connected to the <strong>Control station microcontroller</strong>, and is therefore an I2c slave. If additional sensors or peripherals were to be added (perhaps more sensors), they could also be configured as I2C slaves.</p><p>This master-slave structure is necessary because it guarantees that only one device (the master) controls the communication, avoiding conflicts and ensuring that messages are sent and received in an orderly and predictable way. In summary, the master-slave relationship organizes the roles and responsibilities of each device, making the system both scalable and reliable.</p><h3 id="c-sensor-data-acquisition-and-processing-through-the-i2c-bus" tabindex="-1">c. Sensor Data Acquisition and Processing through the I2C bus <a class="header-anchor" href="#c-sensor-data-acquisition-and-processing-through-the-i2c-bus" aria-label="Permalink to &quot;c. Sensor Data Acquisition and Processing through the I2C bus&quot;">​</a></h3><p>Accurate acquisition and processing of sensor data are essential for monitoring the motion and orientation of the cube. The sensor used in this project is a combined gyroscope and accelerometer: the MPU6050, which communicates with the cube’s microcontroller via the I2C bus.</p><h4 id="acquisition-steps" tabindex="-1">Acquisition Steps: <a class="header-anchor" href="#acquisition-steps" aria-label="Permalink to &quot;Acquisition Steps:&quot;">​</a></h4><ul><li>The microcontroller initializes the sensor by setting up communication parameters and, if necessary, calibrating the sensor to minimize measurement errors.</li><li>At regular intervals, the microcontroller requests raw data from the sensor, including acceleration on each axis (X, Y, Z) and angular velocity (rotation rates) on each axis.</li><li>The I2C protocol ensures that the sensor can reliably respond to requests from the master microcontroller without data collisions.</li></ul><h4 id="processing-steps" tabindex="-1">Processing Steps: <a class="header-anchor" href="#processing-steps" aria-label="Permalink to &quot;Processing Steps:&quot;">​</a></h4><ul><li>The raw sensor readings are converted into meaningful physical units (e.g., acceleration in g’s or m/s², angular velocity in °/s).</li><li>Processing algorithms, such as filtering (e.g., moving average or complementary filter), are applied to reduce noise (<em>small, unwanted variations or disturbances in the sensor data that do not represent the actual movement of the cube</em>) and improve data stability.</li><li>The processed sensor data is then formatted for transmission to the control station over the I2C bus and for display on the LCD.</li></ul><p>This systematic approach to data acquisition and processing enables the system to provide real-time, accurate feedback on the cube’s speed and position, which is crucial for the core functionality of the project.</p><h2 id="_6-programming-the-circuits" tabindex="-1">6. Programming the circuits <a class="header-anchor" href="#_6-programming-the-circuits" aria-label="Permalink to &quot;6. Programming the circuits&quot;">​</a></h2><h2 id="_7-assembly-of-components" tabindex="-1">7. Assembly of components <a class="header-anchor" href="#_7-assembly-of-components" aria-label="Permalink to &quot;7. Assembly of components&quot;">​</a></h2><h2 id="_8-testing-and-validation" tabindex="-1">8. Testing and Validation <a class="header-anchor" href="#_8-testing-and-validation" aria-label="Permalink to &quot;8. Testing and Validation&quot;">​</a></h2><h2 id="_9-helpful-ressources" tabindex="-1">9. helpful Ressources <a class="header-anchor" href="#_9-helpful-ressources" aria-label="Permalink to &quot;9. helpful Ressources&quot;">​</a></h2><ul><li><a href="https://www.kicad.org/" target="_blank" rel="noreferrer">Download KiCad</a></li><li><a href="https://www.autodesk.com/products/fusion-360/download" target="_blank" rel="noreferrer">Download Autodesk Fusion 360</a></li></ul><ul><li><a href="https://docs.arduino.cc/built-in-examples/arduino-isp/ArduinoISP/?queryID=undefined" target="_blank" rel="noreferrer">https://docs.arduino.cc/built-in-examples/arduino-isp/ArduinoISP/?queryID=undefined</a></li><li><a href="https://www.fs-pcba.com/fr/fabrication-dun-circuit-imprime-etape-par-etape/" target="_blank" rel="noreferrer">https://www.fs-pcba.com/fr/fabrication-dun-circuit-imprime-etape-par-etape/</a></li><li><a href="https://youtu.be/uDUp4cLXFrY?si=2rA-MZsFL_sJVutS" target="_blank" rel="noreferrer">https://youtu.be/uDUp4cLXFrY?si=2rA-MZsFL_sJVutS</a></li><li><a href="https://github.com/sdouze/Atmega-Standalone" target="_blank" rel="noreferrer">https://github.com/sdouze/Atmega-Standalone</a></li></ul>',66)]))}const p=t(r,[["render",n]]);export{m as __pageData,p as default};
